import { useInView } from "./helpers";

function PulseDot({ delay = 0 }) {
  return (
    <span style={{ position: "relative", display: "inline-block", width: 14, height: 14 }}>
      <style>{`
        @keyframes pr3{0%{transform:scale(1);opacity:.8}70%{transform:scale(2.4);opacity:0}100%{transform:scale(2.4);opacity:0}}
        @keyframes pd3{0%,100%{transform:scale(1)}50%{transform:scale(1.15)}}
      `}</style>
      <span style={{
        position: "absolute", inset: 0, borderRadius: "50%",
        border: "2px solid #e53e3e",
        animation: `pr3 1.6s ease-out ${delay}s infinite`,
      }} />
      <span style={{
        position: "absolute", inset: 3, borderRadius: "50%",
        background: "#e53e3e",
        animation: `pd3 1.6s ease-in-out ${delay}s infinite`,
      }} />
    </span>
  );
}

function BWIllustration({ index }) {
  const ACCENTS = ["#3b5bdb", "#2f9e44", "#e67700"];
  const accent = ACCENTS[index];
  return (
    <div style={{
      width: "100%", height: 220,
      background: "linear-gradient(145deg,#c8c4c0 0%,#b0ada8 50%,#a0a09a 100%)",
      position: "relative", overflow: "hidden",
      display: "flex", alignItems: "center", justifyContent: "center",
    }}>
      <div style={{
        position: "absolute", width: "100%", height: "100%",
        backgroundImage: `
          radial-gradient(ellipse 80px 55px at 55% 58%,rgba(70,70,70,0.55) 0%,transparent 100%),
          radial-gradient(ellipse 45px 75px at 28% 42%,rgba(55,55,55,0.45) 0%,transparent 100%),
          linear-gradient(180deg,transparent 45%,rgba(35,35,35,0.55) 100%)
        `,
      }} />
      <div style={{
        width: "75%", height: 10, background: "rgba(40,40,40,0.5)",
        borderRadius: 5, position: "absolute", bottom: "35%", zIndex: 2,
      }} />
      <div style={{
        width: 100, height: 70, background: "rgba(45,45,45,0.65)",
        borderRadius: 8, zIndex: 3, position: "relative",
        display: "flex", alignItems: "center", justifyContent: "center",
      }}>
        <div style={{ width: 50, height: 36, borderRadius: 4, background: "rgba(200,200,200,0.35)" }} />
      </div>
      <div style={{
        position: "absolute", right: "12%", top: "15%",
        width: 28, height: 50, background: "rgba(50,50,50,0.6)",
        borderRadius: 5, zIndex: 4,
      }}>
        <div style={{ margin: "4px 4px 0", height: 20, background: "rgba(180,180,180,0.3)", borderRadius: 2 }} />
      </div>
      {/* Red dot */}
      <div style={{
        position: "absolute", top: 12, right: 14,
        width: 14, height: 14, borderRadius: "50%", background: "#e53e3e", zIndex: 5,
      }} />
      {/* Accent triangle */}
      <div style={{
        position: "absolute", bottom: 16, left: 18, width: 0, height: 0,
        borderLeft: "10px solid transparent", borderRight: "10px solid transparent",
        borderBottom: `18px solid ${accent}`, zIndex: 5,
      }} />
    </div>
  );
}

// Tilt angles for each card — looks like hanging without a thread
const TILTS = [-4, 2, -3];

function PillarCard({ title, index, visible }) {
  return (
    <div style={{
      flex: "1 1 280px", maxWidth: 360,
      // Hanging tilt — applied as permanent rotation
      transform: `rotate(${TILTS[index]}deg)`,
      transformOrigin: "50% 0%",
      // Animate in: drop from above + settle into tilt
      opacity: visible ? 1 : 0,
      marginTop: visible ? 0 : -40,
      transition: `opacity 0.65s ${0.18 * index}s cubic-bezier(0.34,1.56,0.64,1),
                   margin-top 0.65s ${0.18 * index}s cubic-bezier(0.34,1.56,0.64,1)`,
    }}>
      <div style={{
        background: "white",
        borderRadius: 18,
        overflow: "hidden",
        boxShadow: "0 8px 40px rgba(0,0,0,0.13), 0 2px 8px rgba(0,0,0,0.07)",
        border: "1px solid #efefef",
      }}>
        {/* Header */}
        <div style={{
          padding: "20px 24px 16px",
          borderBottom: "1px solid #f0f0f0",
          display: "flex", flexDirection: "column", alignItems: "flex-start", gap: 10,
        }}>
          <PulseDot delay={index * 0.4} />
          <h3 style={{
            fontFamily: "'Inter',sans-serif",
            fontSize: 22, fontWeight: 800, letterSpacing: 2,
            color: "#1a1a1a", textTransform: "uppercase",
          }}>{title}</h3>
        </div>
        {/* Illustration */}
        <BWIllustration index={index} />
      </div>
    </div>
  );
}

export default function PillarsSection() {
  const [ref, visible] = useInView(0.2);
  const [headRef, headVisible] = useInView(0.3);

  return (
    <section style={{
      background: "#fafafa", padding: "80px 60px 120px",
      display: "flex", flexDirection: "column", alignItems: "center",
    }}>
      <h2 ref={headRef} style={{
        fontFamily: "'Playfair Display','Georgia',serif",
        fontSize: "clamp(26px,3vw,46px)", fontWeight: 700,
        color: "#1a1a1a", textAlign: "center", marginBottom: 72,
        opacity: headVisible ? 1 : 0,
        transform: headVisible ? "translateY(0)" : "translateY(24px)",
        transition: "opacity 0.6s, transform 0.6s",
      }}>
        The three pillars of the gig economy
      </h2>

      {/* Cards row — extra padding-top so rotated cards don't clip */}
      <div ref={ref} style={{
        display: "flex", gap: 40,
        alignItems: "flex-start", justifyContent: "center", flexWrap: "wrap",
        width: "100%", maxWidth: 1200,
        paddingTop: 20,
      }}>
        {["SPEED", "SCALE", "TRUST"].map((t, i) => (
          <PillarCard key={t} title={t} index={i} visible={visible} />
        ))}
      </div>

      <p style={{
        marginTop: 72,
        fontSize: "clamp(15px,1.2vw,20px)", color: "#333",
        textAlign: "center", maxWidth: 780, lineHeight: 1.75,
        opacity: visible ? 1 : 0,
        transform: visible ? "translateY(0)" : "translateY(20px)",
        transition: "opacity 0.6s 0.5s, transform 0.6s 0.5s",
      }}>
        When e-commerce <strong>first entered India,</strong> people were{" "}
        <span style={{ color: "#e53e3e", fontWeight: 700 }}>reluctant</span>{" "}
        to buy expensive things online.{" "}
        <strong>Today,</strong> however, these platforms have{" "}
        <strong>earned widespread trust.</strong>
      </p>
    </section>
  );
}
